mapper.select:
select

from t_checkup_record cr
left join t_elder e on cr.elder_id = e.id


        and e.name like concat('%', #{elderName}, '%')


        and cr.checkup_type = #{checkupType}


        and cr.risk_level = #{riskLevel}


        and cr.status = #{status}


order by cr.checkup_date desc, cr.id desc
